<template id="variantTemplate"><div class="variant-row grid gap-3 rounded-2xl border bg-slate-50 p-4 md:grid-cols-[1fr_1.2fr_1.2fr_.7fr_auto]"><select data-field="storage" required class="rounded-xl border bg-white px-3 py-3 text-sm"><option value="">Kapasitas</option><option>64GB</option><option>128GB</option><option>256GB</option><option>512GB</option><option>1TB</option></select><select data-field="color" required class="rounded-xl border bg-white px-3 py-3 text-sm"><option value="">Warna</option>@foreach(['Black','White','Space Gray','Silver','Gold','Midnight','Starlight','Blue','Sierra Blue','Pacific Blue','Purple','Deep Purple','Pink','Red','Green','Yellow','Coral','Midnight Green','Natural Titanium','Blue Titanium','White Titanium','Black Titanium'] as $color)<option>{{ $color }}</option>@endforeach</select><input data-field="price" type="number" min="0" required placeholder="Harga" class="rounded-xl border px-3 py-3 text-sm"><input data-field="stock" type="number" min="0" value="0" required placeholder="Stok" class="rounded-xl border px-3 py-3 text-sm"><div class="flex items-center gap-2"><input data-field="is_active_hidden" type="hidden" value="0"><label class="flex items-center gap-1 text-xs font-bold"><input data-field="is_active" type="checkbox" value="1" checked> Aktif</label><button type="button" class="remove-variant rounded-lg bg-red-50 px-2 py-1 text-red-600">×</button></div></div></template>
<label class="mt-6 flex items-center gap-3 rounded-xl bg-slate-50 p-4 text-sm font-bold"><input type="checkbox" name="is_active" value="1" @checked(old('is_active',$product->exists?$product->is_active:true))> Tampilkan produk di website</label><button class="mt-5 w-full rounded-xl bg-[#171816] py-4 font-black text-white">Simpan Produk & Varian</button></form></div></main><script>const rows=document.querySelector('#variantRows'),tpl=document.querySelector('#variantTemplate');function bind(){document.querySelectorAll('.remove-variant').forEach(b=>b.onclick=()=>{if(document.querySelectorAll('.variant-row').length>1)b.closest('.variant-row').remove()})}document.querySelector('#addVariant').onclick=()=>{const i=Date.now(),node=tpl.content.cloneNode(true);node.querySelectorAll('[data-field]').forEach(el=>{const f=el.dataset.field.replace('_hidden','');el.name=`variants[${i}][${f}]`});rows.append(node);bind()};bind();</script></body></html>
